  new: 'PENDING',
  confirmed: 'CONFIRMED',
  cancelled: 'CANCELLED',
  completed: 'COMPLETED',
}

export function normalizeStatus(raw: string): ReservationStatus {
  return STATUS_MAP[raw] ?? 'PENDING'
