        p_tags: input.tags ?? [],
        p_note: input.note || null,
      })
      if (err) throw err

      // Update local state if needed, or caller can just re-fetch
      await fetchServingTables()

      return data
    } catch (e: any) {
      error.value = e.message
      throw e
    } finally {
      loading.value = false
    }
  }

